#include <bits/stdc++.h>
using namespace std;
long long n,c[100005],l=0,t=0,m,p1,s1,s2;
int main(){
	cin>>n;
	for(long long i=1;i<=n;i++)cin>>c[i];
	cin>>m>>p1>>s1>>s2;
	c[p1]+=s1;
	for(long long i=1;i<m;i++)l+=c[i]*(m-i);
	for(long long i=m+1;i<=n;i++)t+=c[i]*(i-m);
	long long g=abs(l-t),ans=m;
	for(long long i=1;i<=n;i++){
		if(i==m)continue;
		if(i<m){
			if(abs(l+(s2*(m-i))-t)<g)g=abs(l+(s2*(m-i))-t),ans=i;
		}else
			if(abs(l-(s2*(i-m))-t)<g)g=abs(l-(s2*(i-m))-t),ans=i;
	}
	cout<<ans;
	return 0;
}
